const nwsData = $("HTTP Request NWS").first().json;
const healthData = $("HTTP Request Health").first().json;

const alerts = nwsData?.features?.slice(0, 3)?.map(f => ({
  event: f.properties?.event,
  headline: f.properties?.headline,
  severity: f.properties?.severity,
  areas: f.properties?.areaDesc
})) || [];

const healthStatus = healthData?.status || "monitoring";
const activeHazards = healthData?.active_hazards || [];

const context = alerts.length > 0
  ? `Active NWS alerts (${alerts.length}): ${alerts.map(a => `${a.event} — ${a.areas}`).join(" | ")}`
  : `No active NWS alerts. System status: ${healthStatus}.`;

const hazardContext = activeHazards.length > 0
  ? `Kahu Ola detecting: ${activeHazards.join(", ")}`
  : "Kahu Ola: routine monitoring, no active hazard signals.";

return [{
  json: {
    context: `${context} ${hazardContext}`,
    alert_count: alerts.length,
    timestamp: new Date().toLocaleString("en-US", { timeZone: "Pacific/Honolulu" })
  }
}];

const response = $input.first().json;
const rawText = response?.candidates?.[0]?.content?.parts?.[0]?.text || "";
const post = rawText.trim();

if (post.length > 300 || !post.includes("kahuola.org")) {
  return [{
    json: {
      post: "Aloha kākou! Kahu Ola is monitoring hazard conditions across Hawaiʻi to keep our ʻohana safe. Stay informed at kahuola.org 🌺",
      is_fallback: true
    }
  }];
}

return [{ json: { post, is_fallback: false } }];
